/* ---------------- Persistência (localStorage) ---------------- */

const STORE_KEY = "s2e_panel_state_v1";

function loadState() {
  try {
    const raw = localStorage.getItem(STORE_KEY);
    if (raw) return JSON.parse(raw);
  } catch (e) {
    console.warn("Falha ao ler estado salvo:", e);
  }
  return { presets: [], activePresetId: null };
}

function saveState(state) {
  try {
    localStorage.setItem(STORE_KEY, JSON.stringify(state));
  } catch (e) {
    console.warn("Falha ao salvar estado:", e);
  }
}

function uid() {
  return Math.random().toString(16).slice(2) + Date.now().toString(16);
}

/* Preset "seed" só para a primeira vez que o painel abre, ilustrando a estrutura */
function seedIfEmpty(state) {
  if (state.presets.length > 0) return state;
  state.presets.push({
    id: uid(),
    name: "Meu Primeiro Preset",
    gameId: "7daystodie",
    createdAt: new Date().toISOString().slice(0, 10),
    triggers: [],
  });
  state.activePresetId = state.presets[0].id;
  return state;
}

